1329	/// rbw-dU empty-arg refusal — BBAA9 contract. Invoking rbw-dU with no
1330	/// argument must die non-zero and emit the rbw-dl pointer (operator
1331	/// discovery for candidate depot project IDs). BUW dispatch merges
1332	/// stderr→stdout via `2>&1` (bud_dispatch.sh:372), so the captured
1333	/// stdout carries the buc_warn/buc_info/buc_tabtarget/buc_die output
1334	/// from rbgp_depot_unmake's no-arg branch (rbgp_Payor.sh:937-942).
1335	///
1336	/// Pure shell, no GCP traffic — refusal lands before authenticate.
1337	fn rbtdrf_rs_unmake_empty_arg_refusal(dir: &Path) -> rbtdre_Verdict {
1338	    let root = match std::env::current_dir() {
1339	        Ok(r) => r,
1340	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1341	    };
1342	
1343	    let tt = match rbtdri_find_tabtarget_global(&root, "rbw-dU") {
1344	        Ok(p) => p,
1345	        Err(e) => return rbtdre_Verdict::Fail(e),
1346	    };
1347	
1348	    let output = match Command::new(&tt).current_dir(&root).output() {
1349	        Ok(o) => o,
1350	        Err(e) => {
1351	            return rbtdre_Verdict::Fail(format!(
1352	                "failed to run {}: {}",
1353	                tt.display(),
1354	                e
1355	            ));
1356	        }
1357	    };
1358	
1359	    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
1360	    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
1361	    let code = output.status.code().unwrap_or(-1);
1362	    let _ = std::fs::write(dir.join("empty-arg-stdout.txt"), &stdout);
1363	    let _ = std::fs::write(dir.join("empty-arg-stderr.txt"), &stderr);
1364	
1365	    if code == 0 {
1366	        return rbtdre_Verdict::Fail(
1367	            "rbw-dU exited 0 with no argument — BBAA9 empty-arg refusal contract violated"
1368	                .to_string(),
1369	        );
1370	    }
1371	
1372	    let combined = format!("{}{}", stdout, stderr);
1373	    if !combined.contains("rbw-dl") {
1374	        return rbtdre_Verdict::Fail(format!(
1375	            "rbw-dU empty-arg refusal did not point at rbw-dl for operator discovery\n\
1376	             stdout:\n{}\n\nstderr:\n{}",
1377	            stdout, stderr
1378	        ));
1379	    }
1380	
1381	    rbtdre_Verdict::Pass
1382	}
