304	
305	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
306	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
307	    let required = match rbtdrm_required_colophons(fixture) {
308	        Some(r) => r,
309	        None => {
310	            return Err(format!(
311	                "rbtd: unknown fixture '{}' — not registered in manifest",
312	                fixture
313	            ));
314	        }
315	    };
316	    for colophon in required {
317	        let found = manifest.split_whitespace().any(|token| token == *colophon);
318	        if !found {
319	            return Err(format!(
320	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
321	                colophon, fixture
322	            ));
323	        }
324	    }
325	    Ok(())
326	}
